(57587, 'email_customizer', 'a:26:{s:8:\"footer_2\";s:108:\"Powered by the <a href=\"https://github.com/hizzle-co/email-customizer\">Email Customizer</a> WordPress plugin\";s:8:\"footer_1\";s:28:\"&copy;{{YEAR}} {{BLOG_NAME}}\";s:8:\"header_2\";s:504:\"<a href=\'https://twitter.com\'><img src=\'http://localhost:8888/barvin/wp-content/plugins/email-customizer/includes/assets/twitter-white.png\' width=\'16\' alt=\'\'></a>&nbsp;<a href=\'https://facebook.com\'><img src=\'http://localhost:8888/barvin/wp-content/plugins/email-customizer/includes/assets/facebook-white.png\' width=\'16\' alt=\'\'></a>&nbsp;<a href=\'https://instagram.com\'><img src=\'http://localhost:8888/barvin/wp-content/plugins/email-customizer/includes/assets/instagram-white.png\' width=\'16\' alt=\'\'></a>\";s:8:\"header_1\";s:13:\"{{BLOG_NAME}}\";s:15:\"container_width\";s:5:\"600px\";s:17:\"header_left_width\";s:5:\"400px\";s:7:\"spacing\";s:3:\"0px\";s:8:\"bg_color\";s:7:\"#f5f5f5\";s:8:\"bg_image\";s:0:\"\";s:4:\"logo\";s:0:\"\";s:16:\"header_font_size\";s:4:\"20px\";s:9:\"header_bg\";s:7:\"#8224e3\";s:17:\"header_text_color\";s:7:\"#ffffff\";s:17:\"header_link_color\";s:7:\"#d6d6d6\";s:14:\"before_content\";s:0:\"\";s:17:\"content_font_size\";s:4:\"16px\";s:10:\"content_bg\";s:7:\"#ffffff\";s:18:\"content_text_color\";s:7:\"#212121\";s:18:\"content_link_color\";s:7:\"#0073aa\";s:16:\"footer_font_size\";s:4:\"13px\";s:9:\"footer_bg\";s:7:\"#ffffff\";s:17:\"footer_text_color\";s:7:\"#aaaaaa\";s:17:\"footer_link_color\";s:7:\"#a1a1a1\";s:10:\"custom_css\";s:377:\".components__inner {\n	border-radius: 0px;\n	text-align: left\n}\n\n.hero-section p,\n.components__footer .components__inner,\n.content {\n	padding: 10px 35px;\n}\n\n.components__header .components__inner {\n	padding: 30px 35px;\n}\n\n.hero-section p {\n	padding: 5px 35px;\n	margin: 0;\n}\n\n.components__inner .footer-1,\n.components__inner .footer-2 {\n	text-align: center;\n	font-weight: 400;\n}\n\n\";s:7:\"content\";s:611:\"<p>All plain emails that WordPress sends from your website will use this template. The email content will appear here</p><p>You can use any of these placeholders in the header and footer texts and they will be replaced by the actual values.</p><ul>\n			<li>{{BLOG_URL}}</li>\n			<li>{{HOME_URL}}</li>\n			<li>{{BLOG_NAME}}</li>\n			<li>{{BLOG_DESCRIPTION}}</li>\n			<li>{{DATE}}</li>\n			<li>{{TIME}}</li>\n			<li>{{YEAR}}</li>\n			<li>{{MONTH}}</li>\n			<li>{{DAY}}</li>\n		</ul><a href=\"https://github.com/hizzle-co/email-customizer/issues/new/choose\">You are welcome to report bugs and request features via GitHub.</a>\";s:12:\"preview_text\";s:0:\"\";}', 'yes'),
