(59549, 'options_body_order', 'Hi [first_name] [last_name]\r\n\r\nThank you for your order! Your custom photo story book is in the works. We hope it helps your kid prepare for whatever lies ahead.\r\n\r\nBooks:\r\n[books]\r\n\r\nTax : [tax]\r\nDiscount: [discount]\r\nTotal: [total]\r\n\r\nThanks and enjoy!', 'no'),
