(59586, 'options_subject_welcome', '🎉📚🎉 Up and Coming Books: You\'re on your way to helping your child prepare for change!', 'no'),
(59587, '_options_subject_welcome', 'field_647a0da1eada8', 'no'),
(59588, 'options_body_welcome', 'Hi, [first_name],\r\n\r\nWelcome to Up and Coming Books! Thank you for creating an account. Log into your account any time to resume working on your book drafts, make edits to books, or order print books.\r\n\r\nYou can find the answers to some common questions in our <a href=\"http://localhost:8888/barvin/frequently-asked-questions/\">FAQ</a>.\r\n\r\nIf you have any other questions, simply reply to this email. We\'re here to help.\r\n\r\n- Rebecca and Boris (Up and Coming Books)', 'no'),
