(178, 10, '_title_how', 'field_6242028d64532'),
(179, 10, 'text_how', 'Help your child anticipate the joys and challenges of new experiences in their very own life with a customized photo story book.\r\n\r\n<b>Create a book in 3 easy steps:</b>\r\n\r\n<b>Step 1:</b> Select a book topic\r\n\r\n<b>Step 2:</b> Answer questions about your child and upload photos\r\n\r\n<b>Step 3:</b> Review and buy your book'),
