(317, 158, '_wp_page_template', 'page-faq.php'),
(319, 158, 'questions_0_question', 'How do I make a personalized book? '),
(320, 158, '_questions_0_question', 'field_62423f8a3dc8a'),
(321, 158, 'questions_0_answer', 'Browse our collection of book topics and select the one that best matches the upcoming event/change. Complete a short questionnaire and upload photographs to customize your child’s change story. We’ll weave everything together into a unique photo storybook, which you can preview before you buy. Your print book will arrive at your doorstep in 6-12 business days.'),
(322, 158, '_questions_0_answer', 'field_62423f943dc8b'),
(323, 158, 'questions_1_question', 'How much does an Up & Coming book cost?  '),
(324, 158, '_questions_1_question', 'field_62423f8a3dc8a'),
(325, 158, 'questions_1_answer', 'Each custom photo storybook is $30 and includes free shipping.'),
(326, 158, '_questions_1_answer', 'field_62423f943dc8b'),
(327, 158, 'questions_2_question', 'How will an Up & Coming personalized photo storybook help my child through a transition?'),
(328, 158, '_questions_2_question', 'field_62423f8a3dc8a'),
(329, 158, 'questions_2_answer', 'Reading an Up & Coming personalized photo storybook with your child in the weeks before a new experience will help them prepare for the joys and challenges of the event. Your child will love looking at photographs of themselves and will become familiar with real people, places, and behaviors they will encounter during the new experience. '),
(330, 158, '_questions_2_answer', 'field_62423f943dc8b'),
