(1258, 158, 'questions_3_question', 'How long does it take for orders to be delivered?'),
(1259, 158, '_questions_3_question', 'field_62423f8a3dc8a'),
(1260, 158, 'questions_3_answer', 'The free shipping included in the price of each book takes approximately 12-13 business days from the day the book is ordered. Speedier shipping options are available for a fee at checkout. '),
(1261, 158, '_questions_3_answer', 'field_62423f943dc8b'),
(1262, 158, 'questions_4_question', 'How will my story look in the printed book?'),
(1263, 158, '_questions_4_question', 'field_62423f8a3dc8a'),
(1264, 158, 'questions_4_answer', 'After you complete the quiz and upload photos, you can preview and edit your story before adding it to your cart. You will see exactly how the text and photos will appear in the 8x8 inch print book.'),
(1265, 158, '_questions_4_answer', 'field_62423f943dc8b'),
