(6653, 2105, 'questions_3_question', 'How long does it take for orders to be delivered?'),
(6654, 2105, '_questions_3_question', 'field_62423f8a3dc8a'),
(6655, 2105, 'questions_3_answer', 'You’ll get your book emailed in PDF format within 2 hours of purchase. Print books take approximately 10 business days to arrive from the day they are ordered, though we cannot guarantee shipping or delivery dates at this time. We offer economy and expedited shipping. '),
(6656, 2105, '_questions_3_answer', 'field_62423f943dc8b'),
(6657, 2105, 'questions_4_question', 'How will my story look in the printed book?'),
(6658, 2105, '_questions_4_question', 'field_62423f8a3dc8a'),
(6659, 2105, 'questions_4_answer', 'To see how your story will be formatted in the 8x8 inch book, log into your account on our website, click on the story title, then click “Print Preview.” You will see exactly how the text and photos will appear in your book. You can then go back and change photos as needed.'),
(6660, 2105, '_questions_4_answer', 'field_62423f943dc8b'),
(6661, 158, 'questions_5_question', 'Can I get a digital copy of my book? '),
(6662, 158, '_questions_5_question', 'field_62423f8a3dc8a'),
(6663, 158, 'questions_5_answer', 'We are working on making PDF versions available in addition to print books. Please check back soon!'),
(6664, 158, '_questions_5_answer', 'field_62423f943dc8b'),
(6665, 2106, 'questions_0_question', 'How do I make a personalized book? '),
(6666, 2106, '_questions_0_question', 'field_62423f8a3dc8a'),
(6667, 2106, 'questions_0_answer', 'Browse our collection of book topics and select the one that best matches the upcoming event/change. Complete a short questionnaire and upload photographs to customize your child’s change story. We’ll weave everything together into a unique photo storybook, which you can preview before you buy. Your print book will arrive at your doorstep in 6-12 business days.'),
(6668, 2106, '_questions_0_answer', 'field_62423f943dc8b'),
(6669, 2106, 'questions_1_question', 'How much does an Up & Coming book cost?  '),
(6670, 2106, '_questions_1_question', 'field_62423f8a3dc8a'),
(6671, 2106, 'questions_1_answer', 'Each custom photo storybook is $30 and includes free shipping.'),
(6672, 2106, '_questions_1_answer', 'field_62423f943dc8b'),
(6673, 2106, 'questions_2_question', 'How will an Up & Coming personalized photo storybook help my child through a transition?'),
(6674, 2106, '_questions_2_question', 'field_62423f8a3dc8a'),
(6675, 2106, 'questions_2_answer', 'Reading an Up & Coming personalized photo storybook with your child in the weeks before a new experience will help them prepare for the joys and challenges of the event. Your child will love looking at photographs of themselves and will become familiar with real people, places, and behaviors they will encounter during the new experience. '),
(6676, 2106, '_questions_2_answer', 'field_62423f943dc8b'),
(6677, 2106, 'questions', '6'),
(6678, 2106, '_questions', 'field_62423ec13dc89'),
(6679, 2106, 'title', 'Build your book now'),
(6680, 2106, '_title', 'field_624240d83dc8e'),
(6681, 2106, 'buttontext', 'Get started'),
(6682, 2106, '_buttontext', 'field_624240dd3dc8f'),
(6683, 2106, 'buttonlink', '127'),
(6684, 2106, '_buttonlink', 'field_624240f23dc90'),
(6685, 2106, 'image', '111'),
(6686, 2106, '_image', 'field_624241003dc91'),
(6687, 2106, 'questions_3_question', 'How long does it take for orders to be delivered?'),
(6688, 2106, '_questions_3_question', 'field_62423f8a3dc8a'),
(6689, 2106, 'questions_3_answer', 'The free shipping included in the price of each book takes approximately 12-13 business days from the day the book is ordered. Speedier shipping options are available for a fee at checkout. '),
(6690, 2106, '_questions_3_answer', 'field_62423f943dc8b'),
(6691, 2106, 'questions_4_question', 'How will my story look in the printed book?'),
(6692, 2106, '_questions_4_question', 'field_62423f8a3dc8a'),
(6693, 2106, 'questions_4_answer', 'After you complete the quiz and upload photos, you can preview and edit your story before adding it to your cart. You will see exactly how the text and photos will appear in the 8x8 inch print book.'),
(6694, 2106, '_questions_4_answer', 'field_62423f943dc8b'),
(6695, 2106, 'questions_5_question', 'Can I get a digital copy of my book? '),
(6696, 2106, '_questions_5_question', 'field_62423f8a3dc8a'),
(6697, 2106, 'questions_5_answer', 'We are working on making PDF versions available in addition to print books. Please check back soon!'),
(6698, 2106, '_questions_5_answer', 'field_62423f943dc8b'),
