(17916, 3842, '_title_testimonials', 'field_624211e856b8a'),
(17917, 3842, 'testimonials_0_testimonial', '“Kids adapt to change better when they’re prepared. These books are excellent preparation.\"'),
(17918, 3842, '_testimonials_0_testimonial', 'field_624212f756b8c'),
(17919, 3842, 'testimonials_0_author', 'ROBERTA ISBERG, MD'),
(17920, 3842, '_testimonials_0_author', 'field_6242130b56b8d'),
(17921, 3842, 'testimonials_1_testimonial', '“The Potty Book has been so helpful to our son\'s potty learning journey. He loves seeing himself and his own bathroom and potty in his book.”'),
(17922, 3842, '_testimonials_1_testimonial', 'field_624212f756b8c'),
(17923, 3842, 'testimonials_1_author', 'ELANA AND NATHAN'),
(17924, 3842, '_testimonials_1_author', 'field_6242130b56b8d'),
(17925, 3842, 'testimonials', '4'),
(17926, 3842, '_testimonials', 'field_6242121656b8b'),
(17927, 3842, 'title_contact', 'Contact Us'),
(17928, 3842, '_title_contact', 'field_6242137656b8f'),
(17929, 3842, 'text_contact', 'If you have any questions or want to suggest a new book topic, please send us a message.'),
(17930, 3842, '_text_contact', 'field_6242138156b90'),
(17931, 3842, 'testimonials_2_testimonial', '\"My 3 year old nephew crushed his ring bearer duties thanks to the awesome book his parents made him with photos of our family and my wedding venue.\"'),
(17932, 3842, '_testimonials_2_testimonial', 'field_624212f756b8c'),
