(26706, 4047, 'text_how', 'Help your child anticipate the joys and challenges of new experiences in their very own life with a customized photo story book.\r\n\r\n<b>Create a book in 3 easy steps:</b>\r\n\r\n<b>Step 1:</b> Select a book topic\r\n\r\n<b>Step 2:</b> Answer questions about your child and upload photos\r\n\r\n<b>Step 3:</b> Review and buy your book'),
(26707, 4047, '_text_how', 'field_6242029564533'),
(26708, 4047, 'image_how', '4045'),
(26709, 4047, '_image_how', 'field_624203e864534'),
(26710, 4047, 'title_testimonials', 'Testimonials'),
(26711, 4047, '_title_testimonials', 'field_624211e856b8a'),
(26712, 4047, 'testimonials_0_testimonial', '“Kids adapt to change better when they’re prepared. These books are excellent preparation.\"'),
(26713, 4047, '_testimonials_0_testimonial', 'field_624212f756b8c'),
(26714, 4047, 'testimonials_0_author', 'ROBERTA ISBERG, MD'),
(26715, 4047, '_testimonials_0_author', 'field_6242130b56b8d'),
(26716, 4047, 'testimonials_1_testimonial', '“The Potty Book has been so helpful to our son\'s potty learning journey. He loves seeing himself and his own bathroom and potty in his book.”'),
(26717, 4047, '_testimonials_1_testimonial', 'field_624212f756b8c'),
(26718, 4047, 'testimonials_1_author', 'ELANA AND NATHAN'),
(26719, 4047, '_testimonials_1_author', 'field_6242130b56b8d'),
(26720, 4047, 'testimonials', '4'),
(26721, 4047, '_testimonials', 'field_6242121656b8b'),
(26722, 4047, 'title_contact', 'Contact Us'),
(26723, 4047, '_title_contact', 'field_6242137656b8f'),
(26724, 4047, 'text_contact', 'If you have any questions or want to suggest a new book topic, please send us a message.'),
(26725, 4047, '_text_contact', 'field_6242138156b90'),
(26726, 4047, 'testimonials_2_testimonial', '\"My 3 year old nephew crushed his ring bearer duties thanks to the awesome book his parents made him with photos of our family and my wedding venue.\"'),
(26727, 4047, '_testimonials_2_testimonial', 'field_624212f756b8c'),
(26728, 4047, 'testimonials_2_author', 'TAMARA'),
(26729, 4047, '_testimonials_2_author', 'field_6242130b56b8d'),
