(1201, 1, '2022-08-17 12:46:30', '2022-08-17 12:46:30', 'a:10:{s:4:\"type\";s:4:\"text\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";}', 'City', 'city', 'publish', 'closed', 'closed', '', 'field_62fce3092a40f', '', '', '2022-08-17 12:46:30', '2022-08-17 12:46:30', '', 104, 'http://localhost:8888/barvin/?post_type=acf-field&p=1201', 2, 'acf-field', '', 0),
