(1279, 1, '2022-09-15 13:40:56', '2022-09-15 13:40:56', 'a:10:{s:4:\"type\";s:4:\"text\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";}', 'Description', 'description-404', 'publish', 'closed', 'closed', '', 'field_63232af70d430', '', '', '2026-03-27 11:20:21', '2026-03-27 11:20:21', '', 1277, 'http://localhost:8888/barvin/?post_type=acf-field&#038;p=1279', 2, 'acf-field', '', 0),
