(1464, 1, '2022-11-18 13:22:14', '2022-11-18 13:22:14', 'a:15:{s:4:\"type\";s:5:\"image\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"return_format\";s:5:\"array\";s:12:\"preview_size\";s:6:\"medium\";s:7:\"library\";s:3:\"all\";s:9:\"min_width\";s:0:\"\";s:10:\"min_height\";s:0:\"\";s:8:\"min_size\";s:0:\"\";s:9:\"max_width\";s:0:\"\";s:10:\"max_height\";s:0:\"\";s:8:\"max_size\";s:0:\"\";s:10:\"mime_types\";s:0:\"\";}', 'Cover background image', 'cover_background_image', 'publish', 'closed', 'closed', '', 'field_637786fb21d39', '', '', '2024-01-11 14:08:37', '2024-01-11 14:08:37', '', 21, 'http://localhost:8888/barvin/?post_type=acf-field&#038;p=1464', 10, 'acf-field', '', 0),
(1542, 1, '2022-11-20 09:30:48', '2022-11-20 09:30:48', 'a:13:{s:4:\"type\";s:6:\"select\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:7:\"choices\";a:3:{s:10:\"In process\";s:10:\"In process\";s:9:\"Completed\";s:9:\"Completed\";s:6:\"Failed\";s:6:\"Failed\";}s:13:\"default_value\";b:0;s:10:\"allow_null\";i:0;s:8:\"multiple\";i:0;s:2:\"ui\";i:0;s:13:\"return_format\";s:5:\"value\";s:4:\"ajax\";i:0;s:11:\"placeholder\";s:0:\"\";}', 'Status', 'status', 'publish', 'closed', 'closed', '', 'field_6379f3b362214', '', '', '2022-11-20 09:30:48', '2022-11-20 09:30:48', '', 1166, 'http://localhost:8888/barvin/?post_type=acf-field&p=1542', 10, 'acf-field', '', 0);
